import json
from src.nodes.base import BaseNode

class JsonParserNode(BaseNode):
    name = "JSON Parser"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/braces.svg"
        # [AUTO-GENERATED-PORTS-START]
        self.add_input("json_str", "string", widget_type="text_area")
        self.add_output("data", "dict")
        # [AUTO-GENERATED-PORTS-END]

    async def execute(self, inputs):
        s = inputs.get('json_str', '{}')
        try:
            await self.set_output("exec_out", True)
            return {'data': json.loads(s)}
        except:
            return {'data': {}}

def register_node():
    return JsonParserNode
